// Get the AI's response text from the SET node
const aiResponse = $json.output || "";  // Use $json instead of $node

// Define the regular expression to match URLs (http or https)
const urlRegex = /(https?:\/\/[^\s\n]+)/g;

// Prepare the text and image arrays for the output
const textResults = [];
const imageResults = [];

// If there are URLs in the response, process them
if (aiResponse.includes('http')) {
    let extractedUrls = aiResponse.match(urlRegex) || [];

    // Remove the URLs from the text (cleaned text without URLs)
    let cleanText = aiResponse.replace(urlRegex, '').trim();

    // Push the cleaned text to textResults array
    if (cleanText) {
        textResults.push(cleanText);
    }

    // Process the extracted URLs and add them as images or links
    extractedUrls.forEach(url => {
        // Check if the URL is an image by its file extension
        const isImage = /\.(jpg|jpeg|png|gif|bmp|svg)$/i.test(url);

        if (isImage) {
            // If it's an image, push it to the imageResults array
            imageResults.push({
                type: 'image',  // This is an image
                url: url.trim()  // Clean up the URL if necessary
            });
        } else {
            // If it's a video or link, append it to the text
            textResults.push(url.trim());  // Add the link to textResults
        }
    });
} else {
    // If no URLs, treat the response as plain text
    textResults.push(aiResponse.trim());
}

// Now, return separate text and image responses (textResults and imageResults arrays)
return {
    textResults: textResults.join(" "),  // Combine all text with links
    imageResults: imageResults,  // Contains image links
};

